import{_ as s,o as n,c as a,ai as i}from"./chunks/framework.CsYGeNYI.js";const g=JSON.parse('{"title":"Messages","description":"","frontmatter":{"summary":"Message flow, sessions, queueing, and reasoning visibility","read_when":["Explaining how inbound messages become replies","Clarifying sessions, queueing modes, or streaming behavior","Documenting reasoning visibility and usage implications"],"title":"Messages"},"headers":[],"relativePath":"concepts/messages.md","filePath":"concepts/messages.md","lastUpdated":1771906665000}'),t={name:"concepts/messages.md"};function o(l,e,r,d,c,p){return n(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="messages" tabindex="-1"><a class="header-anchor" href="#messages">#</a> Messages</h1><p>This page ties together how OpenSoul handles inbound messages, sessions, queueing, streaming, and reasoning visibility.</p><h2 id="message-flow-high-level" tabindex="-1"><a class="header-anchor" href="#message-flow-high-level">#</a> Message flow (high level)</h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Inbound message</span></span>
<span class="line"><span>  -&gt; routing/bindings -&gt; session key</span></span>
<span class="line"><span>  -&gt; queue (if a run is active)</span></span>
<span class="line"><span>  -&gt; agent run (streaming + tools)</span></span>
<span class="line"><span>  -&gt; outbound replies (channel limits + chunking)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>Key knobs live in configuration:</p><ul><li><code>messages.*</code> for prefixes, queueing, and group behavior.</li><li><code>agents.defaults.*</code> for block streaming and chunking defaults.</li><li>Channel overrides (<code>channels.whatsapp.*</code>, <code>channels.telegram.*</code>, etc.) for caps and streaming toggles.</li></ul><p>See <a href="/docs/gateway/configuration">Configuration</a> for full schema.</p><h2 id="inbound-dedupe" tabindex="-1"><a class="header-anchor" href="#inbound-dedupe">#</a> Inbound dedupe</h2><p>Channels can redeliver the same message after reconnects. OpenSoul keeps a short-lived cache keyed by channel/account/peer/session/message id so duplicate deliveries do not trigger another agent run.</p><h2 id="inbound-debouncing" tabindex="-1"><a class="header-anchor" href="#inbound-debouncing">#</a> Inbound debouncing</h2><p>Rapid consecutive messages from the <strong>same sender</strong> can be batched into a single agent turn via <code>messages.inbound</code>. Debouncing is scoped per channel + conversation and uses the most recent message for reply threading/IDs.</p><p>Config (global default + per-channel overrides):</p><div class="language-json5 vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  messages</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    inbound</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      debounceMs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      byChannel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        whatsapp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        slack</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1500</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        discord</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1500</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>Notes:</p><ul><li>Debounce applies to <strong>text-only</strong> messages; media/attachments flush immediately.</li><li>Control commands bypass debouncing so they remain standalone.</li></ul><h2 id="sessions-and-devices" tabindex="-1"><a class="header-anchor" href="#sessions-and-devices">#</a> Sessions and devices</h2><p>Sessions are owned by the gateway, not by clients.</p><ul><li>Direct chats collapse into the agent main session key.</li><li>Groups/channels get their own session keys.</li><li>The session store and transcripts live on the gateway host.</li></ul><p>Multiple devices/channels can map to the same session, but history is not fully synced back to every client. Recommendation: use one primary device for long conversations to avoid divergent context. The Control UI and TUI always show the gateway-backed session transcript, so they are the source of truth.</p><p>Details: <a href="/docs/concepts/session">Session management</a>.</p><h2 id="inbound-bodies-and-history-context" tabindex="-1"><a class="header-anchor" href="#inbound-bodies-and-history-context">#</a> Inbound bodies and history context</h2><p>OpenSoul separates the <strong>prompt body</strong> from the <strong>command body</strong>:</p><ul><li><code>Body</code>: prompt text sent to the agent. This may include channel envelopes and optional history wrappers.</li><li><code>CommandBody</code>: raw user text for directive/command parsing.</li><li><code>RawBody</code>: legacy alias for <code>CommandBody</code> (kept for compatibility).</li></ul><p>When a channel supplies history, it uses a shared wrapper:</p><ul><li><code>[Chat messages since your last reply - for context]</code></li><li><code>[Current message - respond to this]</code></li></ul><p>For <strong>non-direct chats</strong> (groups/channels/rooms), the <strong>current message body</strong> is prefixed with the sender label (same style used for history entries). This keeps real-time and queued/history messages consistent in the agent prompt.</p><p>History buffers are <strong>pending-only</strong>: they include group messages that did <em>not</em> trigger a run (for example, mention-gated messages) and <strong>exclude</strong> messages already in the session transcript.</p><p>Directive stripping only applies to the <strong>current message</strong> section so history remains intact. Channels that wrap history should set <code>CommandBody</code> (or <code>RawBody</code>) to the original message text and keep <code>Body</code> as the combined prompt. History buffers are configurable via <code>messages.groupChat.historyLimit</code> (global default) and per-channel overrides like <code>channels.slack.historyLimit</code> or <code>channels.telegram.accounts.&lt;id&gt;.historyLimit</code> (set <code>0</code> to disable).</p><h2 id="queueing-and-followups" tabindex="-1"><a class="header-anchor" href="#queueing-and-followups">#</a> Queueing and followups</h2><p>If a run is already active, inbound messages can be queued, steered into the current run, or collected for a followup turn.</p><ul><li>Configure via <code>messages.queue</code> (and <code>messages.queue.byChannel</code>).</li><li>Modes: <code>interrupt</code>, <code>steer</code>, <code>followup</code>, <code>collect</code>, plus backlog variants.</li></ul><p>Details: <a href="/docs/concepts/queue">Queueing</a>.</p><h2 id="streaming-chunking-and-batching" tabindex="-1"><a class="header-anchor" href="#streaming-chunking-and-batching">#</a> Streaming, chunking, and batching</h2><p>Block streaming sends partial replies as the model produces text blocks. Chunking respects channel text limits and avoids splitting fenced code.</p><p>Key settings:</p><ul><li><code>agents.defaults.blockStreamingDefault</code> (<code>on|off</code>, default off)</li><li><code>agents.defaults.blockStreamingBreak</code> (<code>text_end|message_end</code>)</li><li><code>agents.defaults.blockStreamingChunk</code> (<code>minChars|maxChars|breakPreference</code>)</li><li><code>agents.defaults.blockStreamingCoalesce</code> (idle-based batching)</li><li><code>agents.defaults.humanDelay</code> (human-like pause between block replies)</li><li>Channel overrides: <code>*.blockStreaming</code> and <code>*.blockStreamingCoalesce</code> (non-Telegram channels require explicit <code>*.blockStreaming: true</code>)</li></ul><p>Details: <a href="/docs/concepts/streaming">Streaming + chunking</a>.</p><h2 id="reasoning-visibility-and-tokens" tabindex="-1"><a class="header-anchor" href="#reasoning-visibility-and-tokens">#</a> Reasoning visibility and tokens</h2><p>OpenSoul can expose or hide model reasoning:</p><ul><li><code>/reasoning on|off|stream</code> controls visibility.</li><li>Reasoning content still counts toward token usage when produced by the model.</li><li>Telegram supports reasoning stream into the draft bubble.</li></ul><p>Details: <a href="/docs/tools/thinking">Thinking + reasoning directives</a> and <a href="/docs/reference/token-use">Token use</a>.</p><h2 id="prefixes-threading-and-replies" tabindex="-1"><a class="header-anchor" href="#prefixes-threading-and-replies">#</a> Prefixes, threading, and replies</h2><p>Outbound message formatting is centralized in <code>messages</code>:</p><ul><li><code>messages.responsePrefix</code>, <code>channels.&lt;channel&gt;.responsePrefix</code>, and <code>channels.&lt;channel&gt;.accounts.&lt;id&gt;.responsePrefix</code> (outbound prefix cascade), plus <code>channels.whatsapp.messagePrefix</code> (WhatsApp inbound prefix)</li><li>Reply threading via <code>replyToMode</code> and per-channel defaults</li></ul><p>Details: <a href="/docs/gateway/configuration#messages">Configuration</a> and channel docs.</p>`,45)])])}const u=s(t,[["render",o]]);export{g as __pageData,u as default};
